jQuery(function($){'use strict';$('.wz-bel-setup-content').on('change','input, select, textarea',function(){var form=$(this).closest('form');var continue_btn=form.find('.button-next');var required_inputs=form.find('input[required], select[required], textarea[required]');var is_complete=!0;required_inputs.each(function(){if(!$(this).val()){is_complete=!1;return!1}});continue_btn.prop('disabled',!is_complete)});$('#wz-bel-not-now').on('click',function(){if(confirm(wzBelWizard.skip_setup)){window.location.href=wzBelWizard.settings_url}});$('.wz-bel-setup-steps li').on('click',function(){var step=$(this).data('step');if(step&&$(this).hasClass('done')){window.location.href=wzBelWizard.settings_url+'&step='+step}})})